import{_ as o,o as a,c as t,a2 as s}from"./chunks/framework.D5wUhsuj.js";const i="/docs/assets/vs-code-spawner.BvPt6SoY.png",n="/docs/assets/vs-code-welcome.DlpGtGdq.png",r="/docs/assets/firefox-enhanced-tracing-prection.CWQk6JGB.png",l="/docs/assets/vscode-k8s-attach-palette.r109YMXm.png",d="/docs/assets/vscode-k8s-extension-attach.DmyRyzLI.png",k=JSON.parse('{"title":"VS Code","description":"","frontmatter":{},"headers":[],"relativePath":"labs/vscode.md","filePath":"labs/vscode.md","lastUpdated":1783462857000}'),c={name:"labs/vscode.md"};function h(p,e,u,m,b,g){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="vs-code" tabindex="-1">VS Code <a class="header-anchor" href="#vs-code" aria-label="Permalink to &quot;VS Code&quot;">​</a></h1><p>VS Code can be used with Labs in two ways.</p><ul><li>Start a browser-based VS Code Lab. The VS Code server runs inside the workspace and is opened through the browser.</li><li>Attach your local VS Code editor to a running Lab pod through Dev Containers. This can be a VS Code Lab or a JupyterLab Lab.</li></ul><p>Both workflows keep code execution inside the prokube workspace, close to workspace storage, cluster services, GPUs, and platform credentials. The difference is mainly where the editor UI runs: in the browser, or in your local VS Code installation.</p><div class="info custom-block"><p class="custom-block-title">VS Code documentation</p><p>For VS Code features that are not specific to prokube, use the upstream <a href="https://code.visualstudio.com/docs" target="_blank" rel="noreferrer">VS Code documentation</a>. For local attachment workflows, see the <a href="https://code.visualstudio.com/docs/devcontainers/attach-container#_attach-to-a-container-in-a-kubernetes-cluster" target="_blank" rel="noreferrer">Dev Containers documentation</a>.</p></div><h2 id="when-to-use-vs-code-labs" tabindex="-1">When to Use VS Code Labs <a class="header-anchor" href="#when-to-use-vs-code-labs" aria-label="Permalink to &quot;When to Use VS Code Labs&quot;">​</a></h2><p>Use browser-based VS Code Labs when you want to:</p><ul><li>work on Python packages, pipeline components, model servers, MCP servers, or agent code in a full editor;</li><li>use a terminal with workspace credentials, <code>kubectl</code>, SDKs, CLIs, and Git already close to the platform;</li><li>use the <a href="https://marketplace.visualstudio.com/items?itemName=GitHub.copilot" target="_blank" rel="noreferrer">GitHub Copilot extension</a> in the browser-based editor when it is available in your selected image;</li><li>build and push container images from inside the cluster when the selected image includes Docker CLI, Buildx, and remote BuildKit support;</li><li>keep a development environment running in the workspace instead of depending on your laptop setup;</li><li>use VS Code in the browser without setting up local cluster access first.</li></ul><p>Use local VS Code attachment when you want your local extensions, keybindings, editor settings, or window management while the code still runs in the Lab pod.</p><p>Use <a href="./jupyterlab.html">JupyterLab</a> instead when the primary artifact is a notebook or exploratory analysis. VS Code is also a good fit for agent-assisted IDE workflows through editor extensions and chat widgets. Use <a href="./opencode.html">OpenCode</a> when you want a more purely agentic setup with long-running agent sessions, terminal-first interaction, or work across multiple projects inside the workspace.</p><h2 id="start-a-browser-based-vs-code-lab" tabindex="-1">Start a Browser-Based VS Code Lab <a class="header-anchor" href="#start-a-browser-based-vs-code-lab" aria-label="Permalink to &quot;Start a Browser-Based VS Code Lab&quot;">​</a></h2><p>Create a VS Code Lab from the Labs page. The launch dialog uses the same basic options as other Labs: name, image, compute resources, storage, configurations, and security options.</p><p><img src="'+i+'" alt="Launch VS Code Lab" loading="lazy"></p><p>For VS Code, the image choice mainly decides the IDE server, language stack, system tools, and preinstalled packages. Choose an image that is close to your workload instead of relying on ad-hoc system changes after startup.</p><p>After the Lab starts, open it from the Labs table. The browser session connects to the VS Code server running inside the Lab pod.</p><p><img src="'+n+'" alt="VS Code Lab" loading="lazy"></p><h3 id="browser-notes" tabindex="-1">Browser Notes <a class="header-anchor" href="#browser-notes" aria-label="Permalink to &quot;Browser Notes&quot;">​</a></h3><p>Browser-based VS Code needs the browser to forward editor shortcuts and terminal input to the web app. If shortcuts such as <code>Command+Shift+P</code> for the command palette do not reach VS Code, or if pasting into the integrated terminal behaves inconsistently, try Chrome. We have had the most reliable results with Chrome for browser-based VS Code Labs.</p><p>In Firefox, disabling <strong>Enhanced Tracking Protection</strong> for the Lab page can help with terminal paste behavior and keyboard handling.</p><img class="pk-docs-small-screenshot" src="'+r+`" alt="Disable Firefox Enhanced Tracking Protection"><p>Typical first steps:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pwd</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">repository-ur</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>The exact tools available depend on the selected image. prokube-maintained images commonly include platform-oriented tooling such as <code>kubectl</code>, Git, shell utilities, Python tooling, SDKs, object-storage helpers, and Docker/Buildx support where applicable.</p><p>VS Code Labs use the same persistence and package-installation model as other Labs. See <a href="./#persistence-and-package-installation">Using Labs</a> for the shared storage rules and <a href="./custom_notebooks.html">Custom Notebooks</a> for repeatable image-based environments.</p><h2 id="platform-workflows-from-vs-code" tabindex="-1">Platform Workflows from VS Code <a class="header-anchor" href="#platform-workflows-from-vs-code" aria-label="Permalink to &quot;Platform Workflows from VS Code&quot;">​</a></h2><p>Because the Lab runs inside your workspace, the terminal can interact with platform services directly when your role allows it.</p><p>Common workflows include:</p><ul><li>editing pipeline component code and submitting pipeline runs;</li><li>developing model servers or inference helpers before moving them to model serving;</li><li>building container images for pipelines, model serving, MCP servers, or agent runtimes when the selected image includes <a href="./#building-container-images">remote BuildKit support</a>;</li><li>inspecting workspace resources with <code>kubectl</code>;</li><li>working with object storage through configured <a href="./#object-storage-from-labs">CLIs or SDKs</a>;</li><li>developing and testing code that later runs in <a href="./../agentops/sandboxes.html">Agent Sandboxes</a>.</li></ul><h2 id="attach-local-vs-code-to-a-running-lab" tabindex="-1">Attach Local VS Code to a Running Lab <a class="header-anchor" href="#attach-local-vs-code-to-a-running-lab" aria-label="Permalink to &quot;Attach Local VS Code to a Running Lab&quot;">​</a></h2><p>If you prefer your local VS Code setup, you can attach it to the container backing a running Lab. The target does not have to be a browser-based VS Code Lab; attaching to a JupyterLab pod is also a common workflow when you want local editor features against the same files and environment.</p><p>Prerequisites:</p><ul><li>a running Lab pod in your workspace;</li><li>local <code>kubectl</code> access to the cluster;</li><li>a kubeconfig available at the default VS Code location, usually <code>~/.kube/config</code> on macOS/Linux or <code>%USERPROFILE%\\.kube\\config</code> on Windows. If you do not have one yet, open the prokube UI, click your user icon in the top-right corner, and use the <code>Download kubeconfig</code> action; see <a href="./../platform/kubernetes.html#download-kubeconfig">Download Kubeconfig</a>;</li><li>the <a href="https://marketplace.visualstudio.com/items?itemName=ms-vscode-remote.remote-containers" target="_blank" rel="noreferrer">Dev Containers extension</a>;</li><li>optionally, the <a href="https://marketplace.visualstudio.com/items?itemName=ms-kubernetes-tools.vscode-kubernetes-tools" target="_blank" rel="noreferrer">Kubernetes extension</a> for a visual pod browser.</li></ul><p>Attach through the command palette:</p><ol><li>Open VS Code locally.</li><li>Run <code>Dev Containers: Attach to Running Kubernetes Container...</code> from the command palette.</li><li>Select the Lab pod in your workspace namespace.</li><li>Select the main Lab container, not the sidecar container such as <code>istio-proxy</code>.</li><li>Open the persistent home directory, usually <code>/home/jovyan</code>.</li></ol><p><img src="`+l+'" alt="Attach local VS Code from the command palette" loading="lazy"></p><p>Attach through the Kubernetes extension:</p><ol><li>Open the Kubernetes explorer in VS Code.</li><li>Navigate to your namespace and find the Lab pod.</li><li>Right-click the main Lab container.</li><li>Select <code>Attach Visual Studio Code</code>.</li><li>Open the persistent home directory, usually <code>/home/jovyan</code>.</li></ol><p><img src="'+d+'" alt="Attach local VS Code from the Kubernetes extension" loading="lazy"></p><p>If the container restarts or becomes unstable after attaching, increase the memory assigned to the Lab. A local VS Code attachment can consume additional memory inside the container.</p><h2 id="working-with-notebooks-from-local-vs-code" tabindex="-1">Working with Notebooks from Local VS Code <a class="header-anchor" href="#working-with-notebooks-from-local-vs-code" aria-label="Permalink to &quot;Working with Notebooks from Local VS Code&quot;">​</a></h2><p>Local VS Code attachment is useful for editing files and running terminals inside the Lab container. For JupyterLab pods, it can also be useful when you want to edit notebooks or supporting Python modules locally while keeping execution in the cluster.</p><p>Notebook kernel integration depends on the selected image and the VS Code extensions installed in the remote container. If notebooks are the main artifact and you do not need local editor integration, use <a href="./jupyterlab.html">JupyterLab</a>. If you edit notebooks from local VS Code, keep them under <code>/home/jovyan</code> or another mounted directory so changes are persisted with the Lab storage.</p><h2 id="operational-notes" tabindex="-1">Operational Notes <a class="header-anchor" href="#operational-notes" aria-label="Permalink to &quot;Operational Notes&quot;">​</a></h2><p>Browser-based VS Code and RStudio Labs may not report idleness in the same way as JupyterLab. Do not rely on automatic idle shutdown unless your administrator has confirmed it for your environment.</p><p>For start, stop, delete, recreate, and troubleshooting behavior, see <a href="./#managing-labs">Managing Labs</a> and <a href="./#troubleshooting-labs">Troubleshooting Labs</a>.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./">Using Labs</a></li><li><a href="./jupyterlab.html">JupyterLab</a></li><li><a href="./opencode.html">OpenCode</a></li><li><a href="./custom_notebooks.html">Custom Notebooks</a></li><li><a href="./../agentops/sandboxes.html">Agent Sandboxes</a></li></ul>',47)])])}const w=o(c,[["render",h]]);export{k as __pageData,w as default};
